def _iter_source_files(root: Path):
    for dirpath, dirnames, filenames in os.walk(root):
        dirnames[:] = [d for d in dirnames if d not in _SKIP_DIRS]
        for name in filenames:
            if any(name.endswith(ext) for ext in _SKIP_EXT):
                continue
            path = Path(dirpath) / name
            if not language_for(str(path)):
                continue  # code search: skip prose/config/binaries
            try:
                if path.stat().st_size > _MAX_BYTES:
                    continue
            except OSError:
                continue
            yield path

def language_for(path: str) -> str:
    for ext, lang in _LANG_BY_EXT.items():
        if path.endswith(ext):
            return lang
    return ""

def chunk_python(path: str, source: str) -> list[Chunk]:
    """Extract every function, method and class as its own chunk."""
    try:
        tree = ast.parse(source)
    except SyntaxError:
        return chunk_generic(path, source, language="python")

    lines = source.splitlines()
    chunks: list[Chunk] = []

    def emit(node: ast.AST, qualname: str, kind: str) -> None:
        start = node.lineno
        end = getattr(node, "end_lineno", start) or start
        code = "\n".join(lines[start - 1 : end])
        doc = ast.get_docstring(node) or ""  # type: ignore[arg-type]
        chunks.append(
            Chunk(path, qualname, kind, start, end, code, doc, "python")
        )

    def walk(node: ast.AST, prefix: str) -> None:
        for child in ast.iter_child_nodes(node):
            if isinstance(child, ast.ClassDef):
                qn = f"{prefix}{child.name}"
                emit(child, qn, "class")
                walk(child, qn + ".")
            elif isinstance(child, (ast.FunctionDef, ast.AsyncFunctionDef)):
                qn = f"{prefix}{child.name}"
                emit(child, qn, "method" if prefix else "function")

    walk(tree, "")
    return chunks

def chunk_file(path: str, source: str) -> list[Chunk]:
    if language_for(path) == "python":
        return chunk_python(path, source)
    return chunk_generic(path, source)

def _format_context(hits: list[Hit]) -> str:
    blocks = []
    for h in hits:
        header = f"# {h.path}:{h.start_line}-{h.end_line}  ({h.kind} {h.symbol})"
        blocks.append(f"{header}\n{h.code}")
    return "\n\n".join(blocks)

def build_prompt(query: str, hits: list[Hit]) -> str:
    return (
        f"Question: {query}\n\n"
        f"Code excerpts retrieved from the repository:\n\n"
        f"{_format_context(hits)}\n\n"
        f"Answer the question using only the excerpts above, citing `path:line`."
    )

def _call_ollama(prompt: str, model: str, host: str) -> str:
    payload = {
        "model": model,
        "stream": False,
        "messages": [
            {"role": "system", "content": _SYSTEM},
            {"role": "user", "content": prompt},
        ],
    }
    req = urllib.request.Request(
        f"{host.rstrip('/')}/api/chat",
        data=json.dumps(payload).encode(),
        headers={"Content-Type": "application/json"},
    )
    try:
        with urllib.request.urlopen(req) as resp:
            data = json.loads(resp.read())
    except urllib.error.HTTPError as exc:
        # Ollama is reachable but returned an error -- surface its actual message.
        try:
            detail = json.loads(exc.read()).get("error", "")
        except Exception:
            detail = ""
        raise RuntimeError(
            f"Local LLM at {host} returned HTTP {exc.code}"
            + (f": {detail}" if detail else "")
            + f". Check the model `{model}` is pulled (`ollama list`) and that "
            "your Ollama install can actually run it."
        ) from exc
    except urllib.error.URLError as exc:
        raise RuntimeError(
            f"Could not reach a local LLM at {host} ({exc}). "
            f"Install Ollama (https://ollama.com), then run "
            f"`ollama pull {model}` and make sure `ollama serve` is running."
        ) from exc
    return data.get("message", {}).get("content", "").strip()

def ask(
    query: str,
    index_root: str = ".",
    k: int = 6,
    model: str = DEFAULT_MODEL,
    host: str = DEFAULT_HOST,
) -> Answer:
    hits = Searcher(index_root).search(query, k=k)
    if not hits:
        raise RuntimeError("Index returned no chunks to reason over.")
    text = _call_ollama(build_prompt(query, hits), model, host)
    return Answer(text=text, model=model, hits=hits)

def tokenize(text: str) -> list[str]:
    """Split text into code-aware subword tokens.

    ``getUserById`` -> ``get user by id``; ``parse_ast_node`` -> ``parse ast
    node``. The original identifier is kept too, so exact matches still rank.
    """
    out: list[str] = []
    for match in _TOKEN_RE.findall(text):
        ident = match.lower()
        if len(ident) > 2 and ident not in _STOPWORDS:
            out.append(ident)
        # split snake_case and camelCase into subwords
        for piece in _CAMEL_RE.sub(" ", match).replace("_", " ").split():
            piece = piece.lower()
            if len(piece) > 2 and piece not in _STOPWORDS and piece != ident:
                out.append(piece)
    return out

class Embedder(ABC):
    """Turn strings into an (n, dim) L2-normalised matrix."""

    dim: int

    @abstractmethod
    def fit(self, corpus: Sequence[str]) -> None:
        """Optional corpus pass (e.g. to learn IDF weights)."""

    @abstractmethod
    def encode(self, texts: Sequence[str]) -> np.ndarray:
        ...

    @property
    @abstractmethod
    def name(self) -> str:
        ...

class LocalHashingEmbedder(Embedder):
    """Hashed TF-IDF over code-aware tokens. No network, no model download."""

    def __init__(self, dim: int = 512) -> None:
        self.dim = dim
        self._idf: dict[str, float] = {}
        self._default_idf: float = 1.0

    @property
    def name(self) -> str:
        return f"local-hashing(dim={self.dim})"

    def fit(self, corpus: Sequence[str]) -> None:
        n_docs = max(len(corpus), 1)
        doc_freq: Counter[str] = Counter()
        for doc in corpus:
            for tok in set(tokenize(doc)):
                doc_freq[tok] += 1
        self._idf = {
            tok: math.log((n_docs + 1) / (df + 1)) + 1.0
            for tok, df in doc_freq.items()
        }
        # unseen query terms get the IDF of a term seen once
        self._default_idf = math.log((n_docs + 1) / 1) + 1.0

    @staticmethod
    def _fnv1a(token: str) -> int:
        """Deterministic 32-bit hash (Python's built-in hash() is salted per
        process, which would scatter index- and query-time tokens into
        different buckets)."""
        h = 0x811C9DC5
        for byte in token.encode("utf-8"):
            h ^= byte
            h = (h * 0x01000193) & 0xFFFFFFFF
        return h

    def _hash(self, token: str) -> tuple[int, int]:
        h = self._fnv1a(token)
        index = h % self.dim
        sign = 1 if (h >> 31) & 1 == 0 else -1  # signed hashing reduces collisions
        return index, sign

    def encode(self, texts: Sequence[str]) -> np.ndarray:
        vectors = np.zeros((len(texts), self.dim), dtype=np.float32)
        for row, text in enumerate(texts):
            counts = Counter(tokenize(text))
            for tok, tf in counts.items():
                idf = self._idf.get(tok, self._default_idf)
                weight = (1.0 + math.log(tf)) * idf  # sublinear tf
                index, sign = self._hash(tok)
                vectors[row, index] += sign * weight
        norms = np.linalg.norm(vectors, axis=1, keepdims=True)
        norms[norms == 0] = 1.0
        return vectors / norms

